import {
  Table,
  TableHead,
  TableHeader,
  TableCaption,
  TableBody,
  TableCell,
  TableRow
} from '@/components/ui/table';
import { Project } from '@/types/Project';
import Image from 'next/image';
import AccordionButtons from '../AccordionItems/AccordionButtons';
import Accordion from '@/components/Accordion';
import Form from '@/components/Form';
import Label from '@/app/(private)/login/components/Label';
import Input from '@/app/(private)/login/components/Input';

export default async function ProjectsTable() {
  // TODO: refatorar fetch e componente
  async function fetchProjects() {
    const response = await fetch(`${process.env.API_URL}/projects`, {
      cache: 'no-cache'
    });
    const data = await response.json();
    const projects: Project[] = data.data;
    return { data, projects };
  }

  const { projects } = await fetchProjects();
  console.log(projects);

  async function createProjectAction(formData: FormData) {
    'use server';
    const projectName = formData.get('projectName') as string;
    const slug = formData.get('slug') as string;
    const description = formData.get('description') as string;
    const projectLink = formData.get('projectLink') as string;
    const githubLink = formData.get('githubLink') as string;
    const projectImageName = formData.get('projectImageName') as string;
    const imageLink = formData.get('imageLink') as string;
    const technologies = formData.get('technologies') as string;
    const techArray = technologies
      .split(',')
      .map((tech) => tech.trim())
      .filter((tech) => tech !== '');

    const response = await fetch(`${process.env.API_URL}/projects`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        projectName,
        slug,
        description,
        projectLink,
        githubLink,
        image: {
          name: projectImageName,
          imageLink
        },
        technologyIds: techArray
      })
    });
  }

  return (
    <>
      <Table className="w-full text-gray lg:w-7/10 lg:justify-self-center lg:text-lg dark:text-white">
        <TableCaption className="pb-5 lg:text-lg">
          Lista de projetos
        </TableCaption>
        <TableHeader>
          <TableRow>
            <TableHead>Nome do Projeto</TableHead>
            <TableHead className="text-center">Slug</TableHead>
            <TableHead>Descrição</TableHead>
            <TableHead>Tecnologias</TableHead>
            <TableHead>Links</TableHead>
            <TableHead className="text-center">Opções</TableHead>
          </TableRow>
        </TableHeader>
        <TableBody>
          {projects.map((project: Project) => (
            <TableRow key={project.id}>
              <TableCell className="w-auto">
                <h3 className="text-sm text-wrap text-gray dark:text-white">
                  {project.projectName}
                </h3>
              </TableCell>
              <TableCell className="text-center wrap-normal">
                {project.slug}
              </TableCell>
              <TableCell className="max-w-[150px]">
                <p className="text-small text-wrap">{project.description}</p>
              </TableCell>
              <TableCell>
                <ul className="flex gap-2 wrap-normal">
                  {project.technologies.map((technology) => (
                    <li key={technology.id}>
                      <Image
                        src={technology.technology.logo.imageLink}
                        alt={technology.technology.logo.name}
                        width={25}
                        height={25}
                      />
                    </li>
                  ))}
                </ul>
              </TableCell>
              <TableCell>
                <ul className="*:py-1">
                  <li>
                    <a href={project.githubLink}> GitHub</a>
                  </li>
                  <li>
                    <a href={project.projectLink}>Demo</a>
                  </li>
                </ul>
              </TableCell>
              <TableCell className="text-center">
                {/* TODO: na função deleteItem, tornar endpoint da requisição dinâmico */}
                <AccordionButtons identifier={project.id} />
              </TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
      <Accordion>
        <Form action={createProjectAction}>
          <Label htmlFor="projectName">Nome do Projeto</Label>
          <Input name="projectName" id="projectName" type="text" />
          <Label htmlFor="slug">Slug</Label>
          <Input name="slug" id="slug" type="text" />
          <Label htmlFor="description">Descrição do Projeto</Label>
          <textarea
            className="focus:border-blue focus:ring-blue w-full rounded-md border border-gray/10 bg-white/10 px-4 py-3 font-roboto-flex text-gray transition placeholder:text-gray/50 focus:ring-1 focus:outline-none dark:border-white/10 dark:bg-black/10 dark:text-white dark:placeholder:text-white/50"
            rows={4}
            name="description"
            id="description"
          ></textarea>
          <Label htmlFor="projectLink">Link da demo</Label>
          <Input name="projectLink" id="projectLink" type="text" />
          <Label htmlFor="githubLink">Link do GitHub</Label>
          <Input name="githubLink" id="githubLink" type="text" />

          <Label htmlFor="projectImageName">Nome da imagem</Label>
          <Input name="projectImageName" id="projectImageName" type="text" />
          <Label htmlFor="imageLink">Link da imagem</Label>
          <Input name="imageLink" id="imageLink" type="text" />
          <Label htmlFor="technologies">
            Tecnologias (IDs separadas por vírgula)
          </Label>
          <Input name="technologies" id="technologies" type="text" />
        </Form>
      </Accordion>
    </>
  );
}
